module RefModule (
    input clk,
    input reset,
    input d,
    input enable,
    output q );reg obf_q_reg;

    always @(posedge clk) begin
        if (reset)
            obf_q_reg <= 1'b0;
        else if (enable)
            obf_q_reg <= d;
    end

    assign q = obf_q_reg;

endmodule
